import{_ as a,c as t,o as i,a1 as o}from"./chunks/framework.DDNAyvCW.js";const n="/assets/general.Dxab6Ale.png",m=JSON.parse('{"title":"General Settings","description":"","frontmatter":{},"headers":[],"relativePath":"docs/settings/general/index.md","filePath":"docs/settings/general/index.md"}'),r={name:"docs/settings/general/index.md"};function l(s,e,h,g,d,u){return i(),t("div",null,e[0]||(e[0]=[o('<h1 id="general-settings" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General Settings&quot;">​</a></h1><p>The Settings page contains various general system configurations, allowing you to customize the appearance, layout, and editor behavior of Chaterm.</p><p><img src="'+n+'" alt=""></p><h2 id="general-settings-1" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings-1" aria-label="Permalink to &quot;General Settings&quot;">​</a></h2><h3 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h3><p>Choose the interface theme:</p><ul><li><strong>Dark Theme</strong>: Suitable for use in dimly lit environments, reduces eye strain</li><li><strong>Light Theme</strong>: Suitable for use in well-lit environments, provides clear visual effects</li><li><strong>Follow System</strong>: Automatically switches theme based on system settings</li></ul><h3 id="background" tabindex="-1">Background <a class="header-anchor" href="#background" aria-label="Permalink to &quot;Background&quot;">​</a></h3><p>Support for enabling custom backgrounds:</p><ul><li><strong>Enable</strong>: Can upload local background images or select system backgrounds</li><li><strong>Disable</strong>: Use default theme background</li></ul><h3 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h3><p>Choose the interface layout:</p><ul><li><strong>Terminal Layout</strong>: Traditional terminal layout</li><li><strong>Agents Layout</strong>: AI Agent priority layout</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><p>Choose the interface language:</p><ul><li><strong>English</strong></li><li><strong>简体中文</strong> (Simplified Chinese)</li><li><strong>繁體中文</strong> (Traditional Chinese)</li><li><strong>Deutsch</strong></li><li><strong>Français</strong></li><li><strong>Italiano</strong></li><li><strong>Português</strong></li><li><strong>Русский</strong> (Russian)</li><li><strong>日本語</strong> (Japanese)</li><li><strong>한국어</strong> (Korean)</li><li><strong>العربية</strong> (Arabic)</li></ul><p>Changes take effect immediately without restarting the application.</p><h3 id="watermark" tabindex="-1">Watermark <a class="header-anchor" href="#watermark" aria-label="Permalink to &quot;Watermark&quot;">​</a></h3><p>Choose to enable or disable the interface watermark:</p><ul><li><strong>Enable</strong>: Display watermark on the interface</li><li><strong>Disable</strong>: Hide interface watermark for a cleaner interface</li></ul><h2 id="editor-settings" tabindex="-1">Editor Settings <a class="header-anchor" href="#editor-settings" aria-label="Permalink to &quot;Editor Settings&quot;">​</a></h2><p>Used to configure the display and behavior of the in-app code/text editor.</p><h3 id="font-size" tabindex="-1">Font Size <a class="header-anchor" href="#font-size" aria-label="Permalink to &quot;Font Size&quot;">​</a></h3><p>Set the font size in the editor. Range: 8–32 pixels.</p><h3 id="line-height" tabindex="-1">Line Height <a class="header-anchor" href="#line-height" aria-label="Permalink to &quot;Line Height&quot;">​</a></h3><p>Set the line height in the editor. Range: 0–48. When set to 0, the editor calculates it automatically.</p><h3 id="font" tabindex="-1">Font <a class="header-anchor" href="#font" aria-label="Permalink to &quot;Font&quot;">​</a></h3><p>Select a monospace font for the editor from the preset font list (e.g. Cascadia Mono).</p><h3 id="tab-size-spaces" tabindex="-1">Tab Size (Spaces) <a class="header-anchor" href="#tab-size-spaces" aria-label="Permalink to &quot;Tab Size (Spaces)&quot;">​</a></h3><p>Set the number of spaces inserted when pressing Tab. Range: 1–8.</p><h3 id="word-wrap" tabindex="-1">Word Wrap <a class="header-anchor" href="#word-wrap" aria-label="Permalink to &quot;Word Wrap&quot;">​</a></h3><ul><li><strong>Enable</strong>: Long lines wrap automatically</li><li><strong>Disable</strong>: Long lines scroll horizontally</li></ul><h3 id="minimap" tabindex="-1">Minimap <a class="header-anchor" href="#minimap" aria-label="Permalink to &quot;Minimap&quot;">​</a></h3><ul><li><strong>Enable</strong>: Show the code minimap on the side of the editor</li><li><strong>Disable</strong>: Hide the minimap</li></ul><h3 id="mouse-wheel-zoom" tabindex="-1">Mouse Wheel Zoom <a class="header-anchor" href="#mouse-wheel-zoom" aria-label="Permalink to &quot;Mouse Wheel Zoom&quot;">​</a></h3><ul><li><strong>Enable</strong>: Use Ctrl + mouse wheel to zoom the editor font</li><li><strong>Disable</strong>: Disable wheel zoom</li></ul>',36)]))}const p=a(r,[["render",l]]);export{m as __pageData,p as default};
